  1→import type { StorybookConfig } from '@storybook/react-native-web-vite';
  2→import type { PluginOption } from 'vite';
  3→import { transformWithEsbuild } from 'vite';
  4→import path from 'path';
  5→
  6→const JSX_JS_PACKAGES = [
  7→  'react-native-flip-card',
  8→  '@semparar/design-system-app',
  9→];
 10→
 11→function jsxInJsPlugin(): PluginOption {
 12→  return {
 13→    name: 'storybook:jsx-in-js',
 14→    enforce: 'pre',
 15→    async transform(code, id) {
 16→      const cleanId = id.replace(/\?.*$/, '');
 17→      if (
 18→        /\.js$/.test(cleanId) &&
 19→        JSX_JS_PACKAGES.some(pkg => id.includes(pkg)) &&
 20→        (code.includes('<') || code.includes('/>'))
 21→      ) {
 22→        return transformWithEsbuild(code, id, {
 23→          loader: 'jsx',
 24→          jsx: 'automatic',
 25→        });
 26→      }
 27→    },
 28→  };
 29→}
 30→
 31→const CJS_IN_ESM_PACKAGES = [
 32→  'react-native-svg/lib/module/',
 33→  'react-native-reanimated/lib/module/',
 34→];
 35→
 36→function cjsToEsmPlugin(): PluginOption {
 37→  return {
 38→    name: 'storybook:cjs-to-esm',
 39→    enforce: 'pre',
 40→    transform(code, id) {
 41→      const cleanId = id.replace(/\?.*$/, '');
 42→      if (
 43→        !(/\.js$/.test(cleanId) && code.includes('module.exports')) ||
 44→        !CJS_IN_ESM_PACKAGES.some(pkg => cleanId.includes(pkg))
 45→      ) {
 46→        return;
 47→      }
 48→
 49→      const objMatch = code.match(/module\.exports\s*=\s*\{([^}]+)\}/);
 50→      if (objMatch) {
 51→        const isIdentifier = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/;
 52→        const entries = objMatch[1]
 53→          .split(',')
 54→          .map(e => e.trim())
 55→          .filter(Boolean)
 56→          .filter(e => {
 57→            const parts = e.split(':').map(p => p.trim());
 58→            return parts.every(p => isIdentifier.test(p));
 59→          })
 60→          .map(e => {
 61→            const parts = e.split(':').map(p => p.trim());
 62→            if (parts.length === 2 && parts[0] !== parts[1]) {
 63→              return `export { ${parts[1]} as ${parts[0]} };`;
 64→            }
 65→            return `export { ${parts[0]} };`;
 66→          });
 67→        const exportsBlock = entries.join('\n');
 68→        return code
 69→          .replace(/["']use strict["'];?\s*/, '')
 70→          .replace(/module\.exports\s*=\s*\{[^}]+\};?/, exportsBlock);
 71→      }
 72→
 73→      const simpleMatch = code.match(
 74→        /module\.exports\s*=\s*([a-zA-Z_$][a-zA-Z0-9_$]*|null|undefined|\d+|'[^']*'|"[^"]*");?/,
 75→      );
 76→      if (simpleMatch) {
 77→        const value = simpleMatch[1];
 78→        const basename = cleanId
 79→          .replace(/^.*\//, '')
 80→          .replace(/\.(web|native)?\.js$/, '');
 81→        const namedExport =
 82→          basename && /^[a-zA-Z_$]/.test(basename)
 83→            ? `export const ${basename} = ${value};\n`
 84→            : '';
 85→        return code
 86→          .replace(/["']use strict["'];?\s*/, '')
 87→          .replace(
 88→            simpleMatch[0],
 89→            `${namedExport}export default ${value};`,
 90→          );
 91→      }
 92→    },
 93→  };
 94→}
 95→
 96→const config: StorybookConfig = {
 97→  stories: ['../src/**/*.stories.@(ts|tsx)'],
 98→
 99→  framework: {
100→    name: '@storybook/react-native-web-vite',
101→    options: {
102→      modulesToTranspile: [
103→        'react-native',
104→        'react-native-reanimated',
105→        'react-native-safe-area-context',
106→        'react-native-gesture-handler',
107→        'react-native-icomoon',
108→        'react-native-flip-card',
109→        'react-native-linear-gradient',
110→        'react-native-status-bar-height',
111→        'react-native-svg',
112→        'react-native-svg-charts',
113→        '@semparar/design-system-app',
114→      ],
115→    },
116→  },
117→
118→  addons: ['@storybook/addon-essentials'],
119→
120→  viteFinal: async config => {
121→    config.plugins = config.plugins || [];
122→    config.plugins.push(jsxInJsPlugin());
123→    config.plugins.push(cjsToEsmPlugin());
124→
